declare(strict_types=1);
$required=['docs/knowledge/README.md','docs/knowledge/project.md','docs/knowledge/squad-chat.md','docs/knowledge/troubleshooting.md','docs/knowledge/deploy.md','docs/knowledge/agent-rules.md','docs/knowledge/updater.md','docs/knowledge/data-integrity.md','docs/knowledge/testing.md','docs/knowledge/image-policy.md','docs/knowledge/product-images.md','docs/knowledge/pricing-integrity.md','docs/knowledge/stock-integrity.md','docs/knowledge/cart-integrity.md','docs/knowledge/order-integrity.md','docs/knowledge/order-request-security.md','docs/knowledge/order-processing.md','docs/knowledge/order-context.md','docs/knowledge/official-site.md','docs/knowledge/legal-source-map.md'];$errors=[];foreach($required as $file){if(!is_file($file)){$errors[]="missing: $file";continue;}if(trim((string)file_get_contents($file))==='')$errors[]="empty: $file";}$rules=(string)@file_get_contents('docs/knowledge/agent-rules.md');foreach(['ok=true','endpoint=squad-chat','providers'] as $needle){if(!str_contains($rules,$needle))$errors[]="agent-rules missing: $needle";}$official=(string)@file_get_contents('docs/knowledge/official-site.md');foreach(['https://www.shopvivaliz.com.br','/p/termos','Visa','Pix'] as $needle){if(!str_contains($official,$needle))$errors[]="official-site missing: $needle";}if($errors){fwrite(STDERR,implode(PHP_EOL,$errors).PHP_EOL);exit(1);}echo "Knowledge validation passed.\n";